broadcast use vstd::std_specs::vec::group_vec_axioms;
if r1@ == self_@[*k] && r1@.valid_physical_address()
    && r2@ == self_@[*k] && r2@.valid_physical_address()
{
    // Chain the two `id@ == self_@[*k]` ensures across r1 and r2.
    assert(r1@ == r2@);
    // AbstractEndPoint is a regular struct, so view equality unfolds to id-field equality.
    assert(r1@.id == r2@.id);
    // r1.view() = AbstractEndPoint{id: r1.id@}, so the previous step is
    // exactly Seq<u8> equality on the underlying Vec<u8> views.
    assert(r1.id@ == r2.id@);
    // Force Seq extensional equality so the trigger fires on the shared view.
    assert(r1.id@ =~= r2.id@);
    // Lift Seq view equality to Vec equality via the broadcast vec axioms.
    assert(r1.id =~= r2.id);
    // EndPoint is a single-field struct, so per-field equality lifts to struct equality.
    assert(r1 == r2);
}
